import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Meta-Meta-Prompting: The Secret to Making AI Agents Work — @garrytan","description":"","frontmatter":{"title":"Meta-Meta-Prompting: The Secret to Making AI Agents Work — @garrytan","author":"Garry Tan（@garrytan）","date":"2026-05-09T00:00:00.000Z","source":"https://x.com/garrytan/status/2053127519872614419","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-09-@garrytan-614419.md","filePath":"research/tweets/2026-05-09-@garrytan-614419.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-09-@garrytan-614419.md"};function i(n,e,h,l,d,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="meta-meta-prompting-the-secret-to-making-ai-agents-work-—-garrytan" tabindex="-1">Meta-Meta-Prompting: The Secret to Making AI Agents Work — @garrytan <a class="header-anchor" href="#meta-meta-prompting-the-secret-to-making-ai-agents-work-—-garrytan" aria-label="Permalink to &quot;Meta-Meta-Prompting: The Secret to Making AI Agents Work — @garrytan&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/garrytan/status/2053127519872614419" target="_blank" rel="noreferrer">https://x.com/garrytan/status/2053127519872614419</a><strong>作者</strong>：Garry Tan（@garrytan） <strong>發布日期</strong>：2026-05-09 <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：Twitter Article <strong>統計</strong>：1944 likes · 234 retweets · 5821 bookmarks · 591738 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>People keep asking me why I am spending my nights coding til 2AM. I have a job and a big one, as CEO of Y Combinator. We help thousands of builders a year to create their dreams of building real startups with real revenue that grow fast.</p><p>In the last 5 months, AI made me a builder again. Late last year, the tools got good enough that I went back to building. Not toy projects. Real systems that compound. I want to show you, with specific examples, what personal AI actually looks like when you stop treating it as a chat window and start treating it as an operating system. And I give it away as open source and in articles like this because I want you to speed up with me.</p><p>This is part of a series: Fat Skills, Fat Code, Thin Harness introduced the core architecture. Resolvers covered the routing table for intelligence. The LOC Controversy was about how every technical person just multiplied themselves by 100x to 1000x. Naked models are stupider argued that the model is the engine, not the car. And the skillify manifesto explained why LangChain raised $160M and gave you a squat rack and dumbell set without a workout plan, and then gave you that workout plan you needed.</p><h2 id="the-book-that-read-me-back" tabindex="-1">The Book That Read Me Back <a class="header-anchor" href="#the-book-that-read-me-back" aria-label="Permalink to &quot;The Book That Read Me Back&quot;">​</a></h2><p>Last month I was reading Pema Chödrön&#39;s <em>When Things Fall Apart</em>. It&#39;s 162 pages, 22 chapters on Buddhist approaches to suffering, groundlessness, and letting go. A friend recommended it during a hard period.</p><p>I asked my AI to do a <strong>book mirror</strong>.</p><p>What that means concretely: The system extracted all 22 chapters of the book, and then, for each chapter, ran a sub-agent that did two things simultaneously: summarized the author&#39;s ideas, and then mapped every idea to my actual life. Not generic &quot;this applies to leaders&quot; pablum. Specific mapping. It knows my family history (immigrant parents, dad from Hong Kong and Singapore, mom from Burma). It knows my professional context (running YC, building open-source tools, mentoring thousands of founders). It knows what I&#39;ve been reading, what I&#39;ve been thinking about at 2am, what my therapists and I are working on.</p><p>The output was a 30,000-word brain page. Each chapter rendered as two columns: what Pema says, and how it maps to what I&#39;m actually living through. The chapter on groundlessness connected to a specific founder conversation I&#39;d had the week before. The chapter on fear mapped to patterns my therapist had identified. The chapter on letting go referenced a late-night session where I&#39;d written about the creative freedom I&#39;d found this year.</p><p>The whole thing took about 40 minutes. A $300/hour therapist reading this book and applying it to my life couldn&#39;t do this in 40 hours, because they don&#39;t have the full graph of my professional context, my reading history, my meeting notes, and my founder relationships all loaded and cross-referenceable.</p><p>I&#39;ve done this with over 20 books now: Amplified (Dion Lim), Autobiography of Bertrand Russell, Designing Your Life, Drama of the Gifted Child, Finite and Infinite Games, Gift from the Sea (Lindbergh), Siddhartha (Hesse), Steppenwolf (Hesse), The Art of Doing Science and Engineering (Hamming), The Dream Machine, The Book on the Taboo Against Knowing Who You Are (Alan Watts), What Do You Care What Other People Think (Feynman), When Things Fall Apart (Pema Chodron), A Brief History of Everything (Ken Wilber), and more. Each one gets richer because the brain gets richer. The second mirror knew about the first. The twentieth knew about all nineteen.</p><h2 id="how-book-mirror-got-better-through-iteration" tabindex="-1">How Book-Mirror Got Better Through Iteration <a class="header-anchor" href="#how-book-mirror-got-better-through-iteration" aria-label="Permalink to &quot;How Book-Mirror Got Better Through Iteration&quot;">​</a></h2><p>The first book mirror I did was terrible. Version 1 had three factual errors about my family. It said my parents were divorced when they weren&#39;t. Said I grew up in Hong Kong when I was born in Canada. Basic stuff that could have damaged trust if I&#39;d shared it.</p><p>So I added a mandatory fact-check step. Every mirror now runs cross-modal evaluation against known facts in the brain before it ships. Opus 4.7 1M catches precision errors. GPT-5.5 catches missing context. DeepSeek V4-Pro catches when something reads as generic.</p><p>Then I upgraded to deep retrieval with GBrain tool use. The original version was good at synthesis but weak on specificity. Version 3 does per-section brain searches. Every right-column entry cites actual brain pages. When the book talks about dealing with difficult conversations, it doesn&#39;t just synthesize general principles. It pulls from my actual meeting notes with specific founders who were having tough conversations with co-founders. Or that idea I had on a Thursday hanging out with my brother James. Or the IM chat I had with my college roommate when I was 19. It&#39;s uncanny.</p><p>This is what <strong>skillification</strong> (using /skillify in GBrain) means in practice. I took the first manual attempt, extracted the repeatable pattern, wrote a tested skill file with triggers and edge cases, and every fix compounded across all future book mirrors.</p><h2 id="skills-that-build-skills" tabindex="-1">Skills That Build Skills <a class="header-anchor" href="#skills-that-build-skills" aria-label="Permalink to &quot;Skills That Build Skills&quot;">​</a></h2><p>Here&#39;s where it gets recursive, and where I think the biggest insight is.</p><p>The system that runs my life didn&#39;t exist as a monolith. It was assembled from skills. And those skills were themselves created by a skill.</p><p>Skillify is a meta-skill that creates new skills. When I encounter a workflow I&#39;m going to repeat, I say &quot;skillify this&quot; and it examines what just happened, extracts the repeatable pattern, writes a tested skill file with triggers and edge cases, and registers it in the resolver. The book-mirror pipeline was skillified from the first time I did it manually. The meeting-prep workflow was skillified after I noticed I was doing the same steps before every call.</p><p>Skills compose. Book-mirror calls brain-ops for storage, enrich for context, cross-modal-eval for quality, and pdf-generation for output. Each skill is focused on one thing. They chain together to create complex workflows. When I improve one skill, every workflow that uses it gets better automatically. No more &quot;forgot to mention this edge case in my prompt.&quot; The skill remembers.</p><h2 id="the-meeting-that-prepped-itself" tabindex="-1">The Meeting That Prepped Itself <a class="header-anchor" href="#the-meeting-that-prepped-itself" aria-label="Permalink to &quot;The Meeting That Prepped Itself&quot;">​</a></h2><p>Demis Hassabis came to YC for a fireside chat. Sebastian Mallaby&#39;s biography of him had just come out.</p><p>I asked the system to prep me.</p><p>In under two minutes it pulled: Demis&#39;s full brain page (which had been accumulating for months from articles, podcast transcripts, and my own notes). His published beliefs about AGI timelines (&quot;50% scaling, 50% innovation,&quot; thinks AGI is 5-10 years away). The Mallaby biography highlights. His stated research priorities (continual learning, world models, long-term memory). Cross-references to things I&#39;ve said publicly about AI. Three demo scripts for showing the brain&#39;s multi-hop reasoning capability during the conversation. And a set of conversation hooks based on where our worldviews overlap and diverge.</p><p>This wasn&#39;t just a better Google search. This was preparation that used my accumulated context about Demis, my own positions, and the strategic goals for the conversation. The system prepped not just facts, but angles.</p><h2 id="what-100-000-pages-of-brain-looks-like" tabindex="-1">What 100,000 Pages of Brain Looks Like <a class="header-anchor" href="#what-100-000-pages-of-brain-looks-like" aria-label="Permalink to &quot;What 100,000 Pages of Brain Looks Like&quot;">​</a></h2><p>I maintain a structured knowledge base with about 100,000 pages. Every person I meet gets a page with a timeline, a state section (what&#39;s currently true), open threads, and a score. Every meeting gets a transcript, a structured summary, and something I call entity propagation: after every meeting, the system walks through every person and company mentioned and updates their brain pages with what was discussed. Every book I read gets a chapter-by-chapter mirror. Every article, podcast, and video I engage with gets ingested, tagged, and cross-referenced.</p><p>The schema is simple. Each page has: compiled truth at the top (the current best understanding), an append-only timeline below (events in chronological order), and raw data sidecars for source material. Think of it as a personal Wikipedia where every page is continuously updated by an AI that was at the meeting, read the email, watched the talk, and ingested the PDF.</p><p>Here&#39;s an example of how this compounds. I meet a founder at office hours. The system creates or updates their person page, their company page, cross-references the meeting notes, checks if I&#39;ve met them before (and surfaces what we discussed last time), checks their application data, pulls their latest metrics, and identifies if any of my portfolio companies or contacts are relevant to their problem. By the time I walk into the next meeting with them, the system has a full context pack ready.</p><p>This is the difference between having a filing cabinet and having a nervous system. The filing cabinet stores things. The nervous system connects them, flags what&#39;s changed, and surfaces what&#39;s relevant to right now.</p><h2 id="the-architecture" tabindex="-1">The Architecture <a class="header-anchor" href="#the-architecture" aria-label="Permalink to &quot;The Architecture&quot;">​</a></h2><p>Here&#39;s how it works. I think this is the right way to build personal AI, and I open-sourced the whole thing so you can build it yourself.</p><p><strong>The harness is thin.</strong> OpenClaw is the runtime. It receives my messages, figures out which skill applies, and dispatches. A few thousand lines of routing logic. It doesn&#39;t know anything about books or meetings or founders. It just routes.</p><p><strong>The skills are fat.</strong> Over 100 of them now, each a self-contained markdown file with detailed instructions for one specific task. You&#39;ve already seen book-mirror and meeting-prep above. Here are a few more that ship with GBrain:</p><ul><li><strong>meeting-ingestion</strong>: After every meeting, it pulls the transcript, creates a structured summary, and then walks through every person and company mentioned and updates their brain pages with what was discussed. The meeting page is not the end product. The entity propagation back to every person and company page is the real value.</li><li><strong>enrich</strong>: Give it a person&#39;s name. It pulls from five different sources, merges everything into a single brain page with career arc, contact info, meeting history, and relationship context. Cited sources on every claim.</li><li><strong>media-ingest</strong>: Handles video, audio, PDF, screenshots, GitHub repos. Transcribes, extracts entities, files to the right brain location. I use this constantly for YouTube videos, podcasts, and voice memos.</li><li><strong>perplexity-research</strong>: Brain-augmented web research. Searches the web via Perplexity, but before synthesizing, checks what the brain already knows so it can tell you what&#39;s actually new vs. what you&#39;ve already captured.</li></ul><p>I have dozens more I&#39;ve built for my own work that I&#39;ll probably open source: email-triage, investor-update-ingest that detects portfolio updates in my email and extracts metrics into company pages, calendar-check for conflict detection and travel impossibility, and a whole journalistic research stack I use for civic work. Each skill encodes operational knowledge that would take a new human assistant months to learn. When someone asks how I &quot;prompt&quot; my AI, the answer is: I don&#39;t. The skills are the prompts.</p><p><strong>The data is fat.</strong> 100,000 pages of structured knowledge in the brain repo. Every person, company, meeting, book, article, and idea I&#39;ve engaged with, all linked, all searchable, all growing every day.</p><p><strong>The code is fat.</strong> The code that feeds it (scripts for transcription, OCR, social media archival, calendar sync, API integrations) matters too, but the data is where the compound value lives. I run more than 100 crons per day that check all the things: social media, Slack, email, whatever I pay attention to, my OpenClaw/Hermes Agents look at for me too.</p><p><strong>The models are interchangeable.</strong> I run Opus 4.7 1M for precision. GPT-5.5 for recall and exhaustive extraction. DeepSeek V4-Pro for creative work and third perspectives. Groq with Llamma for speed. The skill decides which model to call for which task. The harness doesn&#39;t care. When someone asks &quot;which AI model is best,&quot; the answer is: wrong question. The model is just the engine. Everything else is the car.</p><h2 id="the-2am-builder-and-the-compounding-system" tabindex="-1">The 2am Builder and the Compounding System <a class="header-anchor" href="#the-2am-builder-and-the-compounding-system" aria-label="Permalink to &quot;The 2am Builder and the Compounding System&quot;">​</a></h2><p>People ask me about productivity. I don&#39;t think about it that way. What I think about is compounding.</p><p>Every meeting I take adds to the brain. Every book I read enriches the context for the next book. Every skill I build makes the next workflow faster. Every person page I update makes the next meeting prep sharper. The system today is 10x what it was two months ago, and two months from now it&#39;ll be 10x again.</p><p>When I&#39;m still up at 2am coding (and I am, regularly, because AI gave me back the joy of building), I&#39;m not just writing software. I&#39;m adding to a system that gets better every hour. 100 cronjobs 24/7. The meeting ingestion runs automatically. The email triage runs every 10 minutes. The knowledge graph enriches itself from every conversation. The system processes daily transcripts and extracts patterns I missed in real time.</p><p>This is not a writing tool. It&#39;s not a search engine. It&#39;s not a chatbot. It&#39;s a second brain that actually works, not as a metaphor, but as a running system with 100,000 pages, 100+ skills, 15 cron jobs, and the accumulated context of every professional relationship, meeting, book, and idea I&#39;ve engaged with in the last year.</p><p>I open-sourced the whole stack. GStack is the coding skill framework (87,000+ stars) that I used to build it. I still use it as a skill inside OpenClaw/Hermes Agent when the agent needs to code. There&#39;s a great programmable browser (both headed and headless) in there. GBrain is the knowledge infrastructure. OpenClaw and Hermes Agent are the harnesses, you should choose but I usually do both. The data repos are on GitHub.</p><p><strong>The thesis is simple: the future belongs to individuals who build compounding AI systems, not to individuals who use corporate-owned centralized AI tools. The difference is the difference between keeping a journal and having a nervous system.</strong></p><h2 id="how-to-start" tabindex="-1">How to Start <a class="header-anchor" href="#how-to-start" aria-label="Permalink to &quot;How to Start&quot;">​</a></h2><p>If you want to build this:</p><ol><li><strong>Pick a harness.</strong> OpenClaw, Hermes Agent, or build your own from scratch with Pi. Keep it thin. The harness is just the router. Host it on your spare computer at home with Tailscale, or use Render or Railway in the cloud.</li><li><strong>Start a brain with GBrain.</strong> I got inspired by Karpathy&#39;s LLM Wiki, implemented it in OpenClaw, and extended it into GBrain. It&#39;s the best retrieval system I&#39;ve benchmarked (97.6% recall on LongMemEval, beating MemPalace with no LLM in the retrieval loop) and it ships 39 installable skills including everything described in this article. One command to install. A git repo where every person, meeting, article, and idea gets a page.</li><li><strong>Do something interesting.</strong> Don&#39;t start by planning your skill architecture. Start by doing a thing. Write a report. Research a person. Download a season of NBA scores and build a prediction model for your sports bets. Analyze your portfolio. Whatever you actually care about. Do it with your agent, iterate until it&#39;s good, and then run <strong>Skillify</strong> (the meta-skill from earlier) to extract the pattern into a reusable skill. Then run <strong>check_resolvable</strong> to verify the new skill is wired into the resolver. That loop turns one-off work into compounding infrastructure.</li><li><strong>Keep using it and look at the output.</strong> The skill will be mediocre at first. That&#39;s the point. Use it, read what it produces, and when something is off, run <strong>cross-modal eval</strong>: send the output through multiple models and have them score each other on the dimensions you care about. That&#39;s how I caught the factual errors in book-mirror. The fix got baked into the skill, and every mirror since has been clean. In six months you&#39;ll have something no chatbot can replicate, because the value isn&#39;t in the model. It&#39;s in what you&#39;ve taught the system about your specific life, work, and judgment.</li></ol><p>The first thing I built with this system was terrible. The hundredth was something I&#39;d trust with my calendar, my inbox, my meeting prep, and my reading list. The system learned. I learned. The compound curve is real.</p><p>Fat skills. Fat code. Thin harness. The LLM on its own is just an engine. You can build your own car.</p><p>Everything I described here, all the skills, the book mirror pipeline, the cross-modal eval framework, the skillify loop, the resolver architecture, plus 30+ installable skillpacks, is open source and free on GitHub: github.com/garrytan/gbrain. Go build.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：個人 AI 系統的真正力量在於「fat skills + thin harness + compounding data」三層分離架構，模型只是引擎，技能才是可複利的資產。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Skills-as-prompts</strong>：傳統「如何 prompt AI」的問題被重新框架為「如何設計可複用技能」——100+ markdown 技能檔案取代即興提示，每次執行自動套用最新修正。</li><li><strong>Skillify meta-loop</strong>：「技能創造技能」的遞迴架構：手動執行一次 → Skillify 萃取模式 → 寫入技能檔 → 自動路由未來呼叫。這是 cc-workspace 技能設計的直接對標。</li><li><strong>Cross-modal evaluation</strong>：多模型相互評分（Opus 4.7 查精確度、GPT-5.5 查遺漏、DeepSeek 查通用性）是品質保證的核心機制，而非人工 review。</li><li><strong>Compounding brain</strong>：100,000 頁結構化知識庫，schema 為「compiled truth at top + append-only timeline + raw data sidecars」，每次會議/書籍自動更新所有關聯的人員與公司頁面（entity propagation）。</li><li><strong>Thin harness principle</strong>：harness（OpenClaw）只做路由，不懂業務邏輯——與本 workspace 的 Fat Skills, Thin Harness 原則完全一致，提供實際大規模運作的外部驗證。</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li><strong>GBrain 召回率</strong>：97.6% recall on LongMemEval（擊敗 MemPalace，且 retrieval loop 無 LLM）</li><li><strong>100,000 頁</strong>知識庫，<strong>100+ crons/day</strong>，<strong>100+ skills</strong>，<strong>15 cron jobs</strong> 持續運作</li><li><strong>書籍鏡像速度</strong>：22 章書籍完整個人化映射，40 分鐘完成（vs 人工 40 小時以上）</li><li><strong>模型分工</strong>：Opus 4.7 1M（精確度）、GPT-5.5（完整性）、DeepSeek V4-Pro（創意/第三視角）、Groq+Llamma（速度）</li><li><strong>GStack</strong>：87,000+ GitHub stars 的 coding skill framework</li><li><strong>39 installable skills</strong> 隨 GBrain 一鍵安裝</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>可重現性存疑</strong>：文章核心範例（book mirror、entity propagation）高度依賴 GBrain 的私有資料圖譜，97.6% recall 數字未提供完整 benchmark 方法論；一般用戶複製難度遠高於文章暗示的「one command to install」。</li><li><strong>個人化 bias</strong>：所有應用場景（書籍映射、會議準備、知識庫）均以 YC CEO 規模的會議量和資料量為前提，適用性在中小型個人 workspace 需重新評估。</li><li><strong>對 cc-workspace 的直接價值</strong>：Skillify meta-loop（技能萃取技能）和 cross-modal evaluation（多模型相互評分）是可立即在本 workspace 實驗的具體機制；entity propagation 模式對 research/tweets/README.md 自動更新有直接啟示。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9/10</td><td>Skillify meta-loop、cross-modal eval、thin harness 原則均可直接對標 cc-workspace 現有架構</td></tr><tr><td>B. 創新性 (20%)</td><td>8/10</td><td>Skills-as-prompts 與 meta-skill 概念對現有 skill 設計提供遞迴強化框架，非完全新穎但執行細節具體</td></tr><tr><td>C. 證據品質 (20%)</td><td>7/10</td><td>97.6% LongMemEval 數字有具體 benchmark 名稱，但方法論未公開；書籍映射時效等為個人敘述無法驗證</td></tr><tr><td>D. 技術深度 (15%)</td><td>8/10</td><td>架構分層（harness/skills/data/models）、schema 設計（compiled truth + append-only timeline）、cross-modal eval 流程均有足夠實作細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>Fat Skills + Thin Harness 原則跨 harness 通用，但 GBrain 特有整合（entity propagation 等）高度平台相依</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.0/10</strong></td><td>9×0.3 + 8×0.2 + 7×0.2 + 8×0.15 + 7×0.15 = 2.7 + 1.6 + 1.4 + 1.2 + 1.05 = <strong>7.95 ≈ 8.0</strong></td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：核心主張（thin harness、fat skills、cross-modal eval、skillify loop）是通用原則，已與 cc-workspace 現有 CLAUDE.md 哲學高度對齊，建議補充至 <code>.claude/refs/skill-authoring.md</code> 或 <code>harness-design.md</code> 作為外部驗證案例。</p>',69)])])}const m=t(s,[["render",i]]);export{g as __pageData,m as default};
